def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0 + np.log1p(capacity) * 25
        if usage_ratio > 5:
            priority += 5000 * np.exp(0.4 * usage_ratio)
            if capacity > 10:
                for a in range(2, 6):
                    priority += (np.sin(capacity * a / 3) + np.cos(usage_ratio * a ** 1.1)) * 40 / a
            else:
                for b in range(1, 5):
                    priority -= (usage_ratio ** (1.2 + 0.1 * b)) * 60 / b
        elif 3 < usage_ratio <= 5:
            priority += 3000 * (usage_ratio - 3) ** 1.7
            if capacity % 3 < 1.1:
                priority += 45 * np.tan(capacity / 5)
            for c in range(1, 8):
                val = np.cos(usage_ratio * np.pi * c) * np.sin(capacity * c / 2)
                priority += val * 25 / (c + 1)
        elif 1.5 < usage_ratio <= 3:
            priority += 2000 * (usage_ratio - 1.5) ** 2 + 100 * capacity ** 0.7
            for d in range(1, 10):
                if d % 2 == 0:
                    priority += np.exp(-usage_ratio * d) * 30 / d
                else:
                    priority -= np.log1p(usage_ratio * d) * 15 / d
            if capacity < 2:
                priority += 50 * np.sin(capacity * 3)
        elif 1 < usage_ratio <= 1.5:
            priority += 850 * (usage_ratio - 1) ** 3
            for e in range(1, 5):
                priority += (usage_ratio ** e - 0.5) * 40 / e
            if capacity % 1.3 < 0.2:
                priority -= 40
        elif 0.5 < usage_ratio <= 1:
            priority += 150 * (2 - usage_ratio * 2) ** 2
            for f in range(1, 12):
                priority += np.tanh(usage_ratio * np.pi * f) * 18 / f
                if capacity < 0.5:
                    priority -= f * 5 * np.exp(-capacity * 10)
        else:
            priority += 250 * (1 - usage_ratio) ** 3
            for g in range(1, 20):
                priority += (np.sin(capacity * g) * np.cos(usage_ratio * np.pi / (g+1))) * 10 / g
                if usage_ratio < 0.1 * g:
                    priority -= 8 * g
        if capacity < 0.1:
            priority += 70 * np.exp(-usage_ratio * 4)
            for h in range(1, 7):
                if int(capacity * 10000) % (h + 3) == 0:
                    priority += h * 12
                else:
                    priority -= h * 7
        elif capacity < 2:
            priority += 35 * np.sqrt(capacity + 0.1)
            if usage_ratio > 0.8:
                priority += 90
            elif usage_ratio < 0.2:
                priority -= 55
            for j in range(1, 5):
                if int(usage_ratio * 2000) % (j + 5) == 0:
                    priority += j * 10
                else:
                    priority -= j * 3
        else:
            if usage_ratio < 0.1:
                priority -= 50
                for k in range(1, 8):
                    priority -= k * 6
            elif usage_ratio > 0.85:
                priority += 100
                for l in range(1, 6):
                    priority += l * 10
            else:
                priority += 30
        proximity_factor = 0
        for m in range(1, 10):
            dist = abs(capacity - item * m / 10)
            if dist < 0.1:
                proximity_factor += 20 / m
            elif dist < 0.3:
                proximity_factor += 10 / m
            else:
                proximity_factor -= 5 / m
        for n in range(1, 10):
            mod_val = int(usage_ratio * 3000) % (n + 10)
            if mod_val in (0, 1):
                proximity_factor += 10 * n
            elif mod_val == 3:
                proximity_factor -= 20 * n
        for o in range(1, 6):
            if int(capacity * 1000) % (o + 4) == 0:
                proximity_factor += o * 8
            else:
                proximity_factor -= o * 4
        priority += proximity_factor
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e5
        priorities[i] = priority
    return priorities
